"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import Link from "next/link";
import { useQuotes } from "@/context/QuotesContext";
import { Quote } from "@/lib/types";
import { QuoteCard } from "@/components/ui/QuoteCard";
import { Heart, Search, Trash2, Filter, Clock, ArrowDownAZ } from "lucide-react";

type SortOption = "newest" | "oldest" | "author";

export default function LikesPage() {
  const { getLikedQuotes, state, likedCount } = useQuotes();
  const [sortBy, setSortBy] = useState<SortOption>("newest");
  const [filterAuthor, setFilterAuthor] = useState<string>("");

  const likedReactions = getLikedQuotes();

  // Get unique authors from liked quotes
  const uniqueAuthors = Array.from(
    new Set(likedReactions.map((r) => r.quoteSnapshot.author))
  ).sort();

  // Convert reactions to quotes for QuoteCard compatibility
  const likedQuotes: Quote[] = likedReactions.map((r) => ({
    _id: r.quoteId,
    content: r.quoteSnapshot.content,
    author: r.quoteSnapshot.author,
    authorSlug: r.quoteSnapshot.authorSlug,
    tags: r.quoteSnapshot.tags,
    length: r.quoteSnapshot.content.length,
  }));

  // Filter and sort
  let displayQuotes = [...likedQuotes];

  if (filterAuthor) {
    displayQuotes = displayQuotes.filter((q) => q.author === filterAuthor);
  }

  if (sortBy === "oldest") {
    // Reactions are already sorted newest first, so reverse for oldest
    displayQuotes.reverse();
  } else if (sortBy === "author") {
    displayQuotes.sort((a, b) => a.author.localeCompare(b.author));
  }

  // Wait for hydration
  if (!state.hydrated) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-8 sm:py-12">
        <div className="text-center">
          <div className="h-10 w-48 bg-gray-200 dark:bg-gray-700 rounded-lg mx-auto mb-4 animate-pulse" />
          <div className="h-5 w-64 bg-gray-200 dark:bg-gray-700 rounded mx-auto mb-8 animate-pulse" />
          <div className="space-y-6">
            {[1, 2, 3].map((i) => (
              <div
                key={i}
                className="h-40 bg-gray-200 dark:bg-gray-700 rounded-2xl animate-pulse"
              />
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 sm:py-12">
      {/* Header */}
      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="text-center mb-8"
      >
        <h1 className="text-3xl sm:text-4xl font-bold text-gray-900 dark:text-gray-100 mb-4 flex items-center justify-center gap-3">
          <Heart className="w-8 h-8 text-red-500 fill-current" />
          Your Favorites
        </h1>
        <p className="text-gray-600 dark:text-gray-400">
          {likedCount === 0
            ? "Start liking quotes to build your collection"
            : `You have ${likedCount} favorite quote${likedCount !== 1 ? "s" : ""}`}
        </p>
      </motion.div>

      {/* Empty State */}
      {likedCount === 0 && (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="text-center py-16"
        >
          <div className="inline-flex items-center justify-center w-24 h-24 bg-red-50 dark:bg-red-900/20 rounded-full mb-6">
            <Heart className="w-12 h-12 text-red-300 dark:text-red-700" />
          </div>
          <h2 className="text-xl font-semibold text-gray-900 dark:text-gray-100 mb-3">
            No favorites yet
          </h2>
          <p className="text-gray-600 dark:text-gray-400 mb-8 max-w-md mx-auto">
            Explore quotes and click the heart icon to save them here. Your favorites
            are stored locally and will persist even when offline.
          </p>
          <Link
            href="/"
            className="inline-flex items-center gap-2 px-6 py-3 bg-primary-500 hover:bg-primary-600 text-white rounded-xl font-medium transition-colors"
          >
            <Search className="w-4 h-4" />
            Discover Quotes
          </Link>
        </motion.div>
      )}

      {/* Filters & Sort (when there are quotes) */}
      {likedCount > 0 && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="flex flex-col sm:flex-row items-stretch sm:items-center justify-between gap-4 mb-8 p-4 bg-white dark:bg-gray-800 rounded-xl border border-gray-100 dark:border-gray-700"
        >
          {/* Sort Options */}
          <div className="flex items-center gap-2">
            <Filter className="w-4 h-4 text-gray-400" />
            <span className="text-sm text-gray-500 dark:text-gray-400">Sort:</span>
            <div className="flex gap-1">
              {[
                { value: "newest", label: "Newest", icon: Clock },
                { value: "oldest", label: "Oldest", icon: Clock },
                { value: "author", label: "Author", icon: ArrowDownAZ },
              ].map((option) => (
                <button
                  key={option.value}
                  onClick={() => setSortBy(option.value as SortOption)}
                  className={`px-3 py-1.5 text-sm rounded-lg transition-colors ${
                    sortBy === option.value
                      ? "bg-primary-100 dark:bg-primary-900/30 text-primary-700 dark:text-primary-300"
                      : "text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700"
                  }`}
                >
                  {option.label}
                </button>
              ))}
            </div>
          </div>

          {/* Author Filter */}
          {uniqueAuthors.length > 1 && (
            <div className="flex items-center gap-2">
              <span className="text-sm text-gray-500 dark:text-gray-400">Author:</span>
              <select
                value={filterAuthor}
                onChange={(e) => setFilterAuthor(e.target.value)}
                className="px-3 py-1.5 text-sm bg-gray-100 dark:bg-gray-700 border-0 rounded-lg text-gray-700 dark:text-gray-300 focus:ring-2 focus:ring-primary-500"
              >
                <option value="">All Authors</option>
                {uniqueAuthors.map((author) => (
                  <option key={author} value={author}>
                    {author}
                  </option>
                ))}
              </select>
            </div>
          )}
        </motion.div>
      )}

      {/* Results Count (when filtered) */}
      {filterAuthor && (
        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="text-sm text-gray-500 dark:text-gray-400 mb-6"
        >
          Showing {displayQuotes.length} quote{displayQuotes.length !== 1 ? "s" : ""} by{" "}
          {filterAuthor}
          <button
            onClick={() => setFilterAuthor("")}
            className="ml-2 text-primary-600 dark:text-primary-400 hover:underline"
          >
            Clear filter
          </button>
        </motion.p>
      )}

      {/* Quote List */}
      {displayQuotes.length > 0 && (
        <div className="space-y-6">
          <AnimatePresence mode="popLayout">
            {displayQuotes.map((quote, index) => (
              <QuoteCard
                key={quote._id}
                quote={quote}
                animationDelay={index * 0.05}
              />
            ))}
          </AnimatePresence>
        </div>
      )}

      {/* Offline Notice */}
      {likedCount > 0 && (
        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.5 }}
          className="mt-12 text-center text-sm text-gray-400 dark:text-gray-600"
        >
          ✨ Your favorites are stored locally and work offline
        </motion.p>
      )}
    </div>
  );
}
